const handleMobileMenuClickOutside = (event) => {
  // Get the sidebar and hamburger button elements
  const sidebar = document.getElementById('sidebar_section');
  const hamburgerButton = document.querySelector('.Hamburger\\\\ Button');

  // If we're on mobile/tablet view (window width < 768px)
  if (window.innerWidth < 768) {
    // Check if sidebar is open (transformed to 0)
    if (sidebar && sidebar.style.transform === 'translateX(0px)') {
      // If click is outside both the sidebar and hamburger button, close the sidebar
      if (!sidebar.contains(event.target) && 
          (!hamburgerButton || !hamburgerButton.contains(event.target))) {
        sidebar.style.transform = 'translateX(-240px)';
      }
    }
  }
};

